css:
.loader {
  width: 40px;
  aspect-ratio: 1;
  background: linear-gradient(#00AAFF 0 0), linear-gradient(#FF00AA 0 0), #00AAFF;
  background-repeat: no-repeat;
  animation: l1 1.5s infinite;
}
@keyframes l1 {
  0% { background-size: 100% 0, 0 100%; }
  30%, 50% { background-size: 100% 0, 100% 100%; }
  80%, 100% { background-size: 100% 100%, 100% 100%; }
}
